#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2005;
struct cow{int p,c,x;}s[N];
int n,A,B,da[N][N],db[N][N],Ans;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp(cow c1,cow c2){return c1.x<c2.x;}
void Init_DP(){
    for(int i=1;i<=n;i++){
        for(int j=0;j<=A;j++)da[i][j]=da[i-1][j];
        int wei=s[i].x*s[i].c;
        int val=s[i].p;
        for(int j=0;j+wei<=A;j++)
            da[i][j+wei]=max(da[i][j+wei],da[i-1][j]+val);
    }
    for(int i=n;i>=1;i--){
        for(int j=0;j<=B;j++)db[i][j]=db[i+1][j];
        int wei=s[i].c,val=s[i].p;
        for(int j=0;j+wei<=B;j++)
            db[i][j+wei]=max(db[i][j+wei],db[i+1][j]+val);
    }
    return;
}
int main(){
    n=read(),B=read(),A=read();
    for(int i=1;i<=n;i++)
        s[i].p=read(),s[i].c=read(),s[i].x=read();
    sort(s+1,s+n+1,cmp);
    Init_DP();
    for(int d=1;d<=n;d++){
        auto [p,c,x]=s[d];
        for(int u=0;u<=c;u++){
            if(u>B||c-u>B||u*x>A)continue;
            Ans=max(Ans,da[d-1][A-(u*x)]+p+db[d+1][B-(c-u)]);
        }
    }cout<<Ans<<"\n";
    return 0;
}
